import React, { useEffect, useState } from 'react';
import axios from 'axios';

const API_URL = 'https://rrgold.loyalstring.co.in/api/ProductMaster/GetAllLabeledStock';

const Inventory = ({ clientCode }) => {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [labels, setLabels] = useState([]);

  useEffect(() => {
    if (!clientCode) return;
    setLoading(true);
    setError('');
    axios.post(API_URL, { ClientCode: clientCode })
      .then(res => {
        if (Array.isArray(res.data)) {
          setLabels(res.data);
        } else if (res.data && Array.isArray(res.data.Data)) {
          setLabels(res.data.Data);
        } else {
          setLabels([]);
        }
      })
      .catch(err => {
        setError(err.response?.data?.Message || 'Failed to fetch label list');
      })
      .finally(() => setLoading(false));
  }, [clientCode]);

  return (
    <div className="container py-4">
      <h2 className="mb-4" style={{ fontWeight: 600, color: '#333' }}>
        <i className="fas fa-box me-2" style={{ color: '#5470FF' }}></i>
        Inventory Label List
      </h2>
      {loading && <div className="alert alert-info">Loading...</div>}
      {error && <div className="alert alert-danger">{error}</div>}
      {!loading && !error && labels.length === 0 && (
        <div className="alert alert-warning">No labeled stock found.</div>
      )}
      {!loading && !error && labels.length > 0 && (
        <div className="table-responsive">
          <table className="table table-bordered table-hover align-middle" style={{ borderRadius: 12, overflow: 'hidden', background: '#fff' }}>
            <thead className="table-light">
              <tr>
                <th>Item Code</th>
                <th>Product Name</th>
                <th>Category</th>
                <th>Purity</th>
                <th>Gross Wt</th>
                <th>Net Wt</th>
                <th>Branch</th>
                <th>Status</th>
              </tr>
            </thead>
            <tbody>
              {labels.map(label => (
                <tr key={label.Id}>
                  <td>{label.ItemCode}</td>
                  <td>{label.ProductName}</td>
                  <td>{label.CategoryName}</td>
                  <td>{label.PurityName}</td>
                  <td>{label.GrossWt}</td>
                  <td>{label.NetWt}</td>
                  <td>{label.BranchName}</td>
                  <td>
                    <span className={`badge bg-${label.Status === 'Active' ? 'success' : 'secondary'}`}>{label.Status}</span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
};

export default Inventory;
